<section class="admin-page-head"><div><p class="eyebrow">FACTURARE</p><h1>Integrări facturare</h1><p>Motorul intern funcționează fără servicii externe. Secretele conectorilor externi sunt criptate.</p></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="settings-card-grid"><?php foreach($items as $item): $config=json_decode($item['config_json']??'{}',true)?:[]; ?><form class="admin-panel" method="post" action="<?= e(url('/admin/facturare/conectori/'.$item['code'])) ?>"><?= csrf_field() ?><div class="panel-head"><div><p class="eyebrow"><?= e($item['mode']) ?></p><h2><?= e($item['name']) ?></h2></div><span class="status-pill <?= $item['last_health_status']==='healthy'?'success':'' ?>"><?= e($item['last_health_status']) ?></span></div><label>Mediu<select name="environment"><?php foreach(['internal','sandbox','test','live'] as $environment): ?><option <?= $item['environment']===$environment?'selected':'' ?>><?= e($environment) ?></option><?php endforeach; ?></select></label><label>API URL<input name="api_url" value="<?= e($config['api_url']??'') ?>"></label><label>Serie externă<input name="series" value="<?= e($config['series']??'') ?>"></label><label>API key<input type="password" name="api_key" autocomplete="new-password" placeholder="<?= $item['credential_id']?'Păstrată criptat':'' ?>"></label><label>API secret<input type="password" name="api_secret" autocomplete="new-password"></label><label class="check-label"><input type="checkbox" name="is_enabled" value="1" <?= $item['is_enabled']?'checked':'' ?>> Activ</label><label class="check-label"><input type="checkbox" name="is_default" value="1" <?= $item['is_default']?'checked':'' ?>> Implicit</label><button class="admin-button" type="submit">Salvează conectorul</button></form><?php endforeach; ?></div>
